export const category = "redis_extras";
export const questions = [{"category":"redis_extras","difficulty":"medium","type":"short_answer","title":"Redis 7 ACL v2 访问控制","content":"请介绍 Redis 7 ACL v2 的新特性及其配置方法。","answer":"答案：Redis ACL（Access Control List）自 Redis 6.0 引入，在 Redis 7.0（ACL v2）进行了重大增强。ACL 提供了按用户、命令、Key 级别进行权限控制的能力。核心概念：1) User——每个用户有唯一的用户名、认证方式、命令许可、Key 模式、Channel 许可；2) Default User——默认用户默认拥有所有权限；3) 规则语法——ACL SETUSER <username> on ><password> ~<key-pattern> +<command> -<command> +@<category>。Redis 7 ACL v2 新增特性：1) Selectors——允许同一用户定义多组权限规则；2) 用于 Pub/Sub 的 Channel 级别权限；3) 命令日志（ACL LOG）——记录被 ACL 拒绝的访问尝试。\n\n解析：ACL 的配置方式：1) 命令行——ACL SETUSER 动态创建用户（临时生效）；2) 配置文件——在 redis.conf 中写入多条 user 行；3) ACL 文件——设置 aclfile /etc/redis/users.acl，使用 ACL SAVE 持久化（推荐方式）。ACL Categories 包括@admin、@dangerous、@read、@write、@fast、@slow、@pubsub 等。规则顺序从左到右解释。\n\n扩展延伸：Redis ACL 在生产中的最佳实践：为每个应用分配独立用户；避免应用使用 default 用户；对写命令使用精细化控制而非全盘禁止。ACL 的性能影响：ACL 检查在命令处理快路径上增加 O(1) 匹配开销，实测影响 <1%（可忽略）。Redis 7.2+ 的 ACL 增强：支持 nopass 标志、ACL GENPASS 生成加密强度密码、用户过期时间。","hints":["Redis 7 ACL v2 新增的 Selectors 解决了什么问题","ACL Categories（@dangerous、@read、@write）的作用"],"tags":["Redis","ACL","安全"],"id":4105},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis Functions 脚本引擎","content":"请介绍 Redis Functions 的特性及其与 EVAL（Lua 脚本）的对比。","answer":"答案：Redis Functions 是 Redis 7.0 引入的脚本引擎增强特性，允许用户将 Lua 脚本作为 First-Class 数据库对象（Function）注册到 Redis 中，替代传统的 EVAL/EVALSHA 模式。核心区别：1) 管理和部署——EVAL 脚本随调用发送，Redis Server 缓存后返回 SHA1；Functions 通过 FUNCTION LOAD 一次性加载、持久化，重启不丢失。2) 共享和复用——Functions 按 Library（库）组织，直接调用函数名 FCALL mylib.myfunc args。3) 写确定性——Functions 必须声明是否写数据（no-writes 标志），no-writes 函数在 Replica 上也可执行。4) 更安全的沙箱——禁用危险函数，通过 Redis API 访问。\n\n解析：声明 Function 的完整流程：FUNCTION LOAD \"#!lua name=mylib ... redis.register_function('myincr', myincr)\"；执行 FCALL mylib.myincr 1 mykey。Function 库的持久化：加载后自动写入 AOF 和同步到 Replica。库的替换：FUNCTION LOAD REPLACE。Debugging：支持 redis.debug() 函数和 FUNCTION STATS 命令。Function 的超时控制通过 lua-time-limit（默认 5000ms）控制。\n\n扩展延伸：Redis Functions 的适用迁移场景：1) 系统中有大量 EVALSHA 调用且维护困难；2) 脚本需要在主从切换后仍然可用（EVAL 缓存随 Master 切换丢失）；3) 希望在 Replica 上执行只读脚本。Redis Functions 是 Redis Stack 战略的一部分，配合 Triggers and Functions 模块完成复杂事件驱动处理。","hints":["Functions 和 EVAL 在脚本生命周期管理上的核心区别","no-writes 标志如何提高 Replica 的利用率"],"tags":["Redis","Lua","脚本","Functions"],"id":4106},{"category":"redis_extras","difficulty":"medium","type":"short_answer","title":"Redis Sharded Pub/Sub","content":"请介绍 Redis Sharded Pub/Sub（分片发布订阅）的设计目的和工作原理。","answer":"答案：Redis Sharded Pub/Sub 是 Redis 7.0 引入的新功能，用于解决传统 Pub/Sub 在集群模式下消息广播放大（Fan-out Amplification）的问题。传统 Pub/Sub：向某个 Channel 发布消息时，Cluster 中的所有节点都收到该消息并广播给本地订阅者——100 节点集群每个 Pub 消息会在内部分发 99 次。Sharded Pub/Sub：将 Channel 通过 hash slot 映射到具体集群节点，Pub 消息只发送到对应的 Slot 所有者节点。命令：SSUBSCRIBE <channel>、SPUBLISH <channel> <message>。\n\n解析：Sharded Pub/Sub 的适用场景：1) 大规模 Redis Cluster（20+ 节点）中高频率的消息分发；2) 跨 Region Redis 集群——避免全量广播。不适用场景：1) 小集群（<=6 节点）——传统 Pub/Sub 的开销可以接受；2) 需要所有节点都收到消息的场景。注意限制：Sharded Pub/Sub 不支持 Pattern Subscribe（PSUBSCRIBE），不支持 Channel 级别的 ACL。\n\n扩展延伸：Sharded Pub/Sub 在 Redis Stack 中与 RedisGears 和 Triggers 配合使用，实现事件驱动的分布式处理流程。与传统消息队列不同，Redis Pub/Sub 仍然是即发即弃模式——消息不持久化。如果需要可靠消息传递，应结合 Redis Streams。建议在生产环境中逐步将大规模 Pub/Sub 迁移到 SSUBSCRIBE/SPUBLISH。","hints":["传统 Pub/Sub 在集群模式下为什么会产生广播放大问题","Sharded Pub/Sub 是否支持 Pattern Subscribe"],"tags":["Redis","Pub/Sub","集群"],"id":4107},{"category":"redis_extras","difficulty":"medium","type":"short_answer","title":"Redis Streams 消费者组","content":"请介绍 Redis Streams 消费者组（Consumer Group）的工作原理和应用场景。","answer":"答案：Redis Streams 是 Redis 5.0 引入的日志式数据结构，支持消息持久化、消费者组、消息确认（ACK）、阻塞读取等特性。消费者组是 Streams 实现可靠消息消费的核心机制：1) 创建消费者组——XGROUP CREATE mystream mygroup $；2) 维护一个待处理条目列表（PEL——Pending Entry List）；3) 组内消费者通过 XREADGROUP GROUP mygroup consumer1 BLOCK 2000 COUNT 10 STREAMS mystream > 读取消息。核心操作：XACK——从 PEL 中移除消息；XCLAIM——消费者崩溃时其他消费者接管消息；XPENDING——查看挂起的消息。\n\n解析：消费者组与 Kafka 消费者组的概念映射：Stream 对应 Kafka Topic；Consumer Group 对应 Kafka Consumer Group；PEL 对应未提交的 Offsets。差异：1) Redis Streams 每条消息有唯一自动生成的 ID（<ms>-<seq>），Kafka 使用 Offset；2) Redis 没有 Kafka 的 Rebalance 机制——需要手动使用 XCLAIM；3) 消息自动过期（MAXLEN 近似删除）。\n\n扩展延伸：Redis Streams 与 Pub/Sub 的核心区别：Streams 消息持久化（Pub/Sub 不持久）；Streams 支持重新消费历史消息；Streams 支持 ACK 机制。Streams 适用场景：任务队列、事件源、活动流、CDC 缓存同步。限制：单个 Stream 的规模受内存限制。Redis 7.4 引入的 Streams 增强包括 AUTO-CLAIM 机制。","hints":["PEL（Pending Entry List）在消费者组中的作用","XCLAIM 在消费者故障时如何工作"],"tags":["Redis","Streams","消息队列"],"id":4108},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"RedisTimeSeries 时序数据模块","content":"请介绍 RedisTimeSeries 模块的数据结构、查询语法和典型应用场景。","answer":"答案：RedisTimeSeries 是 Redis Stack 中的时序数据模块，提供了专门的时间序列数据结构（TimeSeries）和丰富的聚合查询能力。数据结构：每个 TimeSeries Key 表示一个时间序列——由多个按时间戳排序的样本（timestamp-value pair）组成。特性：1) 自动过期——RETENTION 参数自动删除旧样本；2) 标签索引——通过 LABELS 附加快捷属性，支持按标签进行多对多的元查询（TS.MRANGE）；3) 降采样压缩——自动创建降采样规则（TS.CREATERULE），如原始数据每 1 秒 1 条，自动降采样为每 5 分钟 1 条的平均值/最大值/最小值；4) 双精度浮点支持。\n\n解析：命令示例：TS.CREATE sensor:temp RETENTION 86400000 LABELS type temp room 101；TS.ADD sensor:temp 1620000000000 25.5；TS.RANGE sensor:temp 1620000000000 1620100000000 AGGREGATION avg 300000。跨序列查询 TS.MRANGE：按标签匹配查询多个序列。TS.MGET 用于批量获取最新样本。RedisTimeSeries 的内存优化使用 128-bit 压缩表示，典型的压缩比约 1:5~1:20。\n\n扩展延伸：RedisTimeSeries 的应用场景：1) 物联网/传感器数据——通过标签索引支持亿级设备的元查询；2) 应用指标监控（API 延迟、错误率）——结合 Grafana 的 Redis Data Source；3) 金融时序。与 InfluxDB/Prometheus 对比：RedisTimeSeries 数据完全驻留在内存中，查询为亚毫秒级，但存储成本远高于列式压缩。建议架构：RedisTimeSeries 作为热数据缓存层，保留最近 N 小时/天的数据。","hints":["RedisTimeSeries 的标签索引（LABELS）如何实现多维度查询","Compaction/Rule 自动降采样的作用"],"tags":["Redis","时序数据","RedisTimeSeries"],"id":4109},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis 内存淘汰策略实现","content":"请详细介绍 Redis 的 8 种内存淘汰策略及其底层实现原理。","answer":"答案：Redis 在内存达到 maxmemory 限制时，根据配置的策略淘汰 key。\n\n8 种淘汰策略：\n\n1. noeviction（默认）：\n   - 不淘汰，写入直接返回错误\n   - 适用：缓存不允许丢失的场景\n\n2. allkeys-lru：\n   - 对所有 key 使用近似 LRU 淘汰\n   - 实现：维护一个 16/24 大小的候选池，采样（默认 5 个）淘汰最久未用的\n   - 近似 LRU 而非精确 LRU（节省内存）\n\n3. volatile-lru：\n   - 仅对设置了 TTL 的 key 使用近似 LRU\n\n4. allkeys-random：\n   - 对所有 key 随机淘汰\n   - 实现：在哈希表中随机选 key 删除\n   - 适用：缓存被均匀访问，无明显热点\n\n5. volatile-random：\n   - 仅对设置了 TTL 的 key 随机淘汰\n\n6. volatile-ttl：\n   - 淘汰 TTL 最短的 key（即将过期的）\n   - 实现：采样后选最小剩余 TTL\n\n7. allkeys-lfu（4.0+）：\n   - 对所有 key 使用 LFU（最不经常使用）淘汰\n\n8. volatile-lfu（4.0+）：\n   - 仅对设置了 TTL 的 key 使用 LFU\n\nLRU 近似实现（Approximated LRU）：\n- 精确 LRU 需要维护双向链表 + 哈希表（内存开销大）\n- Redis 的做法：\n  1. 每个对象维护一个 24-bit 的 lru 字段（记录上次访问时间戳，精度分钟级）\n  2. 淘汰时：从哈希表随机选 N 个 key（默认采样 5 个）\n  3. 放入淘汰候选池（大小 16），保留最久未用的\n  4. 从池中选择最合适的淘汰\n\nLFU 实现：\n- 复用 lru 字段（24-bit）拆分为：\n  - 高 16 位：上次衰减时间（分钟级时间戳）\n  - 低 8 位：计数器（对数增长，最大值 255）\n- 计数器增长：每次访问根据概率递增（近似对数增长）\n- 计数器衰减：访问频率随时间衰减（基于时间差）\n\n扩展延伸：Redis 4.0 引入 LFU 后，大多数场景推荐使用 LFU（allkeys-lfu）。LFU 比 LRU 更抗突发流量冲击（一次批量查询不会把热点数据冲掉）。","hints":["8 种策略：noeviction, *-lru, *-lfu, *-random, volatile-ttl（两维度：范围×算法）","近似 LRU：对象存 24-bit 访问时间戳，淘汰时采样（默认 5 个）+ 候选池（16 个）","LFU：24-bit 拆为 16-bit 衰减时间 + 8-bit 对数计数器，抗突发访问"],"tags":["Redis","内存淘汰","LRU","LFU"],"id":4117},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis 主从复制与哨兵机制","content":"请介绍 Redis 主从复制的完整流程以及哨兵（Sentinel）实现高可用的原理。","answer":"答案：Redis 从 2.8 版本开始支持完整的主从复制和哨兵高可用方案。\n\n主从复制流程：\n\n1. 连接建立：\n   - SLAVEOF 命令触发从节点发起连接\n   - 从节点发送 PING 检查主节点状态\n   - 身份认证（如果主节点配置了密码）\n\n2. 全量复制（首次连接或断连太久）：\n   - 主节点执行 BGSAVE 生成 RDB\n   - 主节点将 RDB 发送给从节点\n   - 从节点清空数据 + 加载 RDB\n   - 主节点将复制缓冲区的增量命令发给从节点\n\n3. 增量复制（断线重连）：\n   - 从节点记录主节点的 replid 和 offset\n   - 主节点维护 repl_backlog_buffer（环形缓冲区）\n   - 断线后从节点发送 PSYNC replid offset\n   - 如果 offset 仍在 backlog 中 → 增量同步\n   - 如果 offset 已不在 backlog 中 → 全量同步\n\n4. 命令传播：\n   - 主节点每收到写命令，写入复制缓冲区\n   - 异步发送给从节点\n   - 从节点确认接收\n\n哨兵（Sentinel）高可用：\n\n架构：\n- Sentinel 是一个独立的进程，监控所有 Redis 节点\n- 通常部署 3 个 Sentinel（奇数个，避免脑裂）\n\n工作流程：\n1. 监控：通过 PING 定期检测主节点和从节点状态\n2. 主观下线（SDOWN）：\n   - 单个 Sentinel 节点在 down-after-milliseconds 内未收到 PONG\n3. 客观下线（ODOWN）：\n   - 多数 Sentinel（quorum）认为主节点下线\n4. Leader 选举：\n   - Sentinel 间通过 Raft 选出一个 Leader\n5. 故障转移：\n   - 从从节点中选一个新主节点（优先级高 → offset 新 → runid 小）\n   - Sentinel Leader 发送 SLAVEOF NO ONE 给新主\n   - 其他从节点指向新主\n   - 原主恢复后成为新主的从节点\n\n扩展延伸：主从复制是异步的（Redis 默认），可能导致主节点写入成功但从节点尚未收到。Redis 3.2 引入 WAIT 命令实现同步复制（等待至少 N 个从节点确认）。","hints":["全量复制：RDB + 增量命令；增量复制：基于 repl_backlog_buffer 环形缓冲区的 offset 追赶","哨兵流程：PING 监控 → SDOWN（单节点断连）→ ODOWN（多数确认）→ Raft 选 Leader → 故障转移","主从复制默认异步，WAIT 命令可实现同步复制"],"tags":["Redis","主从复制","Sentinel","高可用"],"id":4118},{"category":"redis_extras","difficulty":"medium","type":"short_answer","title":"Redis Pipeline vs 事务 vs Lua 脚本","content":"请对比 Redis Pipeline、事务（MULTI/EXEC）和 Lua 脚本三种批量操作方式的差异。","answer":"答案：三种方式都能实现 Redis 的批量操作，但语义和适用场景不同。\n\nPipeline（管道）：\n\n原理：\n- 客户端将多个命令打包发送，减少网络 RTT\n- 服务端按顺序执行并返回所有结果\n\n特点：\n- 不保证原子性（命令之间可能插入其他客户端的命令）\n- 不保证所有命令都执行（中间命令失败不影响后续）\n- 减少网络延迟（批量发送）\n- 适合：无依赖关系的批量操作\n\n事务（MULTI/EXEC/WATCH）：\n\n原理：\n- MULTI 开始事务，命令入队不执行\n- EXEC 触发批量执行\n- WATCH 实现乐观锁（监视 key 变化）\n\n特点：\n- 原子性（EXEC 时所有命令连续执行，中间不插入其他命令）\n- 不支持回滚（如果命令有语法错误，全部不执行；运行时错误不影响其他）\n- 所有命令在 EXEC 前仅入队（不执行），所以不能做条件逻辑\n- 适合：需要原子执行的命令集合\n\nLua 脚本（EVAL/EVALSHA）：\n\n原理：\n- 将 Lua 脚本上传到 Redis 服务端执行\n- 脚本中调用 Redis 命令\n\n特点：\n- 原子性（脚本执行期间其他命令不插入）\n- 支持逻辑控制（if/else/for 等编程逻辑）\n- 脚本可以读取当前数据做决策\n- 脚本结果可以直接作为后续命令的输入\n- 适合：需要条件判断和计算逻辑的复杂操作\n\n对比：\n| 维度 | Pipeline | 事务 | Lua |\n|------|----------|------|-----|\n| 原子性 | 否 | 是 | 是 |\n| 条件逻辑 | 否 | 否 | 是 |\n| 可读入数据 | 否 | 否 | 是 |\n| 回滚 | 部分失败 | 部分失败 | 全部失败 |\n| 网络 RTT | 1 | 2（入队+执行） | 1 |\n\n选择建议：\n- 简单批量、无依赖 → Pipeline\n- 需要原子性、无条件 → 事务\n- 需要条件判断、复杂逻辑 → Lua 脚本\n\n扩展延伸：Redis 7.0 引入 Functions（脚本库），替代 EVAL 的脚本管理方式。Functions 支持脚本复用、自动同步到从节点、可管理（FUNCTION LIST/FUNCTION DELETE）。","hints":["Pipeline：打包减少网络 RTT，不保证原子性","事务：MULTI/EXEC 保证原子性但无条件逻辑，不支持回滚","Lua 脚本：原子性 + 条件逻辑 + 可读数据，功能最强"],"tags":["Redis","Pipeline","Lua","事务"],"id":4119},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis Cluster 哈希槽与重分片","content":"请介绍 Redis Cluster 的哈希槽（Hash Slot）机制以及在线重分片（Resharding）的原理。","answer":"答案：Redis Cluster 通过哈希槽实现去中心化的数据分片。\n\n哈希槽（Hash Slot）机制：\n\n分片方案：\n- 固定 16384 个哈希槽（0~16383）\n- 每个 key 通过 CRC16(key) % 16384 计算所属槽位\n- 每个节点负责一部分哈希槽\n- 槽位到节点的映射关系存储在 Cluster 总线中\n\n哈希标签（Hash Tag）：\n- 如果 key 包含 {} 大括号，只对 {} 内的内容计算哈希\n- 例：{user:123}:profile 和 {user:123}:cart 在同一个槽\n- 作用：将相关 key 强制分配到同一节点（支持多 key 操作）\n\n槽位分配：\n- 每个节点广播自己的槽位信息（通过 Gossip 协议）\n- 客户端通过 CLUSTER SLOTS 命令获取槽位映射\n- 客户端缓存映射表，直接路由到对应节点\n- 重定向：节点返回 MOVED 错误（永久迁移）或 ASK 错误（临时迁移）\n\n在线重分片（Resharding）流程：\n\n1. 迁移准备：\n   - 确定要迁移的槽位和目标节点\n   - 通过 CLUSTER SETSLOT 标记迁移状态（migrating/importing）\n\n2. 数据迁移：\n   - 源节点：MIGRATE 命令将 key 批量移动到目标节点\n   - MIGRATE 是原子操作（RESTORE + DEL）\n   - 迁移过程中，key 的读写仍然可以处理\n\n3. 增量迁移：\n   - 迁移期间，如果 key 在源节点被修改\n   - 增量触发重新迁移\n   - 重复直到所有 key 迁移完成\n\n4. 完成：\n   - 通知所有节点更新槽位映射\n   - CLUSTER SETSLOT 标记槽位稳定\n\n迁移期间的请求处理：\n- 源节点收到该槽位的请求时：\n  - 如果 key 已迁移 → 返回 ASK 重定向到目标节点\n  - 如果 key 尚未迁移 → 直接处理\n- 目标节点收到该槽位的请求时：\n  - 如果在导入状态 → 处理\n  - 如果不在导入状态 → MOVED 到源节点\n\n扩展延伸：16384 这个数字选取得很有讲究——每个节点的心跳包需要包含槽位位图（16384 bit ≈ 2KB），2KB 的心跳包刚好适合大多数 MTU 限制。更大的槽位数会增大心跳开销。","hints":["16384 固定槽位：CRC16(key) % 16384，Cluster 总线中维护槽位→节点映射","哈希标签 {}：大括号内内容计算哈希，相关 key 绑定到同一节点","重分片：MIGRATE 命令源→目标，MIGRATE/ASK 重定向处理迁移中的请求"],"tags":["Redis","Cluster","哈希槽","重分片"],"id":4120},{"category":"redis_extras","difficulty":"medium","type":"short_answer","title":"Redis 缓存雪崩、穿透与击穿","content":"请介绍 Redis 缓存的雪崩、穿透、击穿三种故障模式及对应的解决方案。","answer":"答案：这是 Redis 缓存的三个经典问题，发生原因和解决方案各不相同。\n\n缓存雪崩（Cache Avalanche）：\n\n现象：大量缓存在同一时间过期，请求全部打到数据库\n\n原因：\n- 大量 key 设置了相同的过期时间（如同时写入时 TTL 相同）\n- 缓存节点宕机\n\n解决方案：\n1. 过期时间加随机值：base_TTL + random(0, 300s)\n2. 多级缓存：本地缓存（Caffeine）→ Redis → 数据库\n3. 热点 key 不过期（后台异步更新）\n4. 熔断/降级：数据库压力大时直接返回旧缓存\n\n缓存穿透（Cache Penetration）：\n\n现象：请求的数据在缓存和数据库中都不存在，每次请求都打到数据库\n\n原因：\n- 恶意攻击（遍历不存在的 ID）\n- 查询的条件本身没有数据\n\n解决方案：\n1. 缓存空值（Null Object）：即使查不到数据也缓存空结果（短 TTL）\n2. 布隆过滤器（Bloom Filter）：请求前先判断 key 是否存在\n3. 参数校验：过滤明显不合法的请求（如负数 ID）\n\n缓存击穿（Cache Breakdown / Hotspot Invalidation）：\n\n现象：单个热点 key 过期，大量并发请求同时打到数据库\n\n原因：\n- 热点 key 过期瞬间，高并发场景下所有请求都回源数据库\n\n解决方案：\n1. 互斥锁（Mutex Key）：只让一个请求回源，其他等待\n   - SETNX 获取锁，成功后回源重建缓存\n   - 其他请求自旋等待\n2. 热点 key 不过期：\n   - 物理上不设过期时间\n   - 逻辑过期：数据内嵌过期时间，异步线程检查更新\n3. 提前预热：在高峰期前主动刷新热点 key\n\n对比：\n| 问题 | 原因 | 方案 |\n|------|------|------|\n| 雪崩 | 大量 key 同时过期 | 随机 TTL、多级缓存 |\n| 穿透 | 查不存在的数据 | 空值缓存、布隆过滤器 |\n| 击穿 | 热点 key 过期 | 互斥锁、热点不过期 |\n\n扩展延伸：这三个问题可能叠加出现——比如雪崩时大量 key 过期 + 击穿的某个热点 key，数据库同时承受多种压力。实际生产中需要多层防御：本地缓存 + Redis + 熔断 + 限流 + 数据库连接池保护。","hints":["雪崩：大量 key 同时过期 → 随机 TTL、多级缓存；宕机 → 熔断降级","穿透：查不存在的数据 → 空值缓存、布隆过滤器","击穿：热点 key 过期 → 互斥锁重建、热点不过期（逻辑过期）"],"tags":["Redis","缓存雪崩","缓存穿透","缓存击穿"],"id":4121},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis 异步持久化 AOF 重写与 RDB 持久化对比","content":"请详细对比 Redis RDB 和 AOF 两种持久化方式的实现原理和选型建议。","answer":"答案：RDB 是快照持久化，AOF 是追加日志持久化，两者有不同的性能和可靠性特征\n\n解析：RDB（Redis Database Backup）通过 fork 子进程将内存数据全量写入临时 RDB 文件，写完后原子替换旧文件。COW（写时复制）机制使子进程和父进程共享物理内存页，子进程持久化期间父进程修改的页会被复制。AOF（Append Only File）将每条写命令追加到 AOF 缓冲区，根据 appendfsync 策略（always/everysec/no）刷盘。AOF 文件随运行时间增长，由 bgrewriteaof 命令触发重写（同样 fork 子进程读取内存生成最小命令集重写 AOF）。Redis 4.0+ 支持混合持久化（aof-use-rdb-preamble yes）：AOF 重写时先生成 RDB 快照写入 AOF 文件头，后续增量命令用 AOF 格式追加。\n\n扩展延伸：选型建议：1）允许少量数据丢失（分钟级）选 RDB，适合缓存场景 2）需要高可靠性选 AOF（everysec 最多丢 1 秒数据）3）最佳实践：两者都开启（RDB 做定期备份 + AOF 做崩溃恢复）。AOF 文件比 RDB 文件大且有更多写入开销，但可读性强适合手动分析。RDB 在加载大数据集时比 AOF 快（AOF 需逐条回放命令）。fork 子进程在使用大内存时（>10GB）可能阻塞主进程数十到数百毫秒，需要合理设置 auto-aof-rewrite-percentage 避免频繁重写。RDB 不适合做恢复的唯一手段因为两次快照间数据丢失较多。","hints":["RDB 的 COW 机制在写密集场景下会有什么影响","AOF 的 everysec 最多丢 1 秒数据的依据是什么"],"tags":["Redis","持久化","RDB","AOF"],"id":4122},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis Cluster 节点通信协议","content":"请解释 Redis Cluster 节点之间的通信机制，包括 Gossip 协议和配置同步。","answer":"答案：Redis Cluster 节点间通过 Gossip 协议异步交换节点状态信息\n\n解析：每个 Redis 节点维护 cluster 状态信息（节点列表、角色（master/slave）、hash slot 分配）。节点通过两个 TCP 端口工作：数据端口（6379）+ 集群总线端口（16379，用于节点间通信）。Gossip 消息类型包括：MEET（新节点加入）、PING（探测节点健康）、PONG（回复 PING/MEET 或主动广播）、FAIL（投票判定节点下线）。每秒随机选择 5 个节点发送 PING，传输自身状态 + 已知的 2-3 个其他节点随机信息。如果在规定时间内（cluster-node-timeout）没有收到 PONG 响应，则标记疑似下线（PFAIL）。多个 master 节点在超时时间内对疑似节点投票，半数以上同意则标记 FAIL。\n\n扩展延伸：Hash Slot 分配：16384 个 hash slot 均匀分布到 N 个 master 节点，槽位分配信息通过 Gossip 同步。节点间关系记录在 cluster-state 中，客户端通过 CLUSTER NODES / CLUSTER SLOTS 获取映射关系后缓存到本地进行智能路由。槽位迁移：通过 resharding 将 slot 从源节点移动到目标节点，迁移过程中源节点维护 migrating 状态，目标节点维护 importing 状态，客户端收到 MOVED 重定向后更新本地缓存。新节点加入流程：redis-cli --cluster add-node 发起 MEET 消息，Gossip 协议扩散到全集群。Redis 7.0 引入集群连接共享（cluster link），减少大规模集群的元数据流量。","hints":["PFAIL 和 FAIL 两种下线状态有什么区别","16384 个 hash slot 这个数字是怎么确定的"],"tags":["Redis","Cluster","Gossip"],"id":4123},{"category":"redis_extras","difficulty":"medium","type":"choice","title":"Redis 原子操作","content":"以下哪个 Redis 操作组合是原子执行的？","options":["A) GET + SET","B) WATCH + MULTI + EXEC","C) WATCH + GET + SET","D) MULTI + GET + DISCARD"],"answer":"B","hints":["WATCH 配合事务实现了乐观锁的效果，CAS 语义"],"tags":["Redis","事务","原子性"],"id":4124},{"category":"redis_extras","difficulty":"medium","type":"short_answer","title":"Redis 内存碎片处理","content":"请解释 Redis 内存碎片的成因以及清理策略。","answer":"答案：Redis 内存碎片来自申请和释放内存不连续导致的空闲内存无法被有效利用\n\n解析：Redis 使用 jemalloc 作为默认内存分配器，当键值对频繁创建和删除、大小各异时会产生外部碎片（空闲内存小块分散在各处无法合并为大块）。通过 INFO memory 的 mem_fragmentation_ratio（used_memory_rss / used_memory）指标判断碎片率：该值约 1.0-1.2 表示正常，>1.5 表示碎片严重，<1.0 表示内存换出。Redis 4.0+ 提供 MEMORY PURGE 命令尝试释放碎片内存，但常用策略是：1）开启自动碎片整理 activedefrag yes（6.0+ 默认关闭）2）配置 active-defrag-threshold-lower（碎片率触发阈值，默认 10%）3）配置 active-defrag-cycle-min/max（CPU 占用比例）\n\n扩展延伸：自动碎片整理原理：主线程利用空闲时间对碎片区域进行数据搬移（复制-释放），类似 GC 的标记-压缩，但逐一移动 key/value 是耗时操作，需要限制对主线程的影响。碎片整理对高负载实例有一定性能影响（尤其是 active-defrag-cycle-max 设置过大时）。预防碎片的最佳方式：1）使用大小接近的 key/value 减少跨类别碎片 2）定期重启实例（从 RDB/AOF 重新加载可以彻底解决碎片）3）考虑使用 Redis on Flash 等具有独立内存管理的方案。注意：RSS 是进程实际占用的物理内存，used_memory 是 Redis 自身统计的申请总量，两者的差值并非全部是碎片，也包括 jemalloc 的内部碎片和元数据开销。","hints":["mem_fragmentation_ratio 大于 1.0 正常，但超过多少需要处理","自动碎片整理对 Redis 性能的影响"],"tags":["Redis","内存","优化"],"id":4125},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis 7.0 新特性","content":"请介绍 Redis 7.0 引入的核心新特性和改进。","answer":"答案：Redis 7.0 是功能丰富的重大版本更新，包含多项性能优化和新功能\n\n解析：1）Function（函数）— 在服务端运行 Lua 脚本的更好方式，支持库管理（FUNCTION LOAD/FUNCTION LIST），脚本可作为一等公民独立于 Redis 版本管理，比 EVAL 更强大 2）ACL v2 — 细粒度命令权限控制（如限制 String 类但允许 GET/SET），支持 key 空间权限通配符 3）集群改进 — 集群连接共享（Cluster Link Management）在大规模集群中减少元数据连接数；节点间消息自动压缩减少带宽 4）AOF 改进 — 支持 AOF 文件时间戳和可选 CRC32 校验，改进 AOF 加载可靠性 5）新命令 — ZINTERCARD（集合交集的基数估算）、LCS（最长公共子序列）、SPUBLISH（Sharded Pub/Sub 跨集群发布）等 6）性能提升 — 网络处理栈优化，单线程模式下可达 15% 吞吐提升。\n\n扩展延伸：Sharded Pub/Sub 解决传统 Pub/Sub 在集群模式下消息广播的开销问题——每条消息只在单个 slot 范围内发布，接收者也只订阅该 slot，跨节点消息不广播。Function 和 EVAL 对比：Function 可以管理多个库（每个库包含多个函数），支持函数列表和代码复用；EVAL 每次发脚本字符串难以管理。Redis 7.2 进一步引入了 Redis Stack（集成了 Search/JSON/TimeSeries 等模块）、自动调参（Auto-tuning of active-defrag 参数）、RDB 文件兼容性增强。Redis 7.4 引入向量搜索能力。","hints":["Function 替代 EVAL 有什么好处","Sharded Pub/Sub 解决集群模式的什么问题"],"tags":["Redis","新特性","版本"],"id":4126},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis 主从复制缓冲区","content":"解释 Redis 主从复制中的缓冲区机制，包括客户端输出缓冲区（Client Output Buffer）和复制积压缓冲区（Replication Backlog）。PSYNC 和全量同步的切换条件是什么？缓冲区溢出如何处理？","answer":"Redis 主从复制涉及两类缓冲区：\\n\\n1. 复制积压缓冲区（Replication Backlog）：\\n- 由参数 repl-backlog-size 控制（默认 1MB）。\\n- 主库在内存中维护一个环形缓冲区，记录最近执行的写命令。\\n- 从库断线重连时，如果偏移量仍在 backlog 范围内，执行 PSYNC（部分重同步），只发送断连期间缺失的命令。\\n- 如果从库的偏移量已被 backlog 覆盖（断连太久），则触发全量重同步。\\n- repl-backlog-ttl 控制没有从库时 backlog 的保留时间。\\n\\n2. 客户端输出缓冲区（Client Output Buffer）：\\n- 由 client-output-buffer-limit replica 参数控制（hard limit / soft limit）。\\n- 当从库消费速度跟不上主库的写入速度时，缓冲区会增大。\\n- 如果超过 hard limit 或持续超过 soft limit，主库会断开该从库连接。\\n- 对于慢从库或网络延迟高的场景，需要适当增大缓冲区限制。\\n\\n同步切换：\\n- PSYNC（部分同步）：repl_backlog 中还有从库丢失的命令。\\n- 全量同步：从库首次连接、repl_backlog 溢出、或从库落后太多。\\n- 全量同步成本高：主库需 Fork 子进程生成 RDB 快照，传输给从库。","hints":["repl-backlog-size 设置太小会有什么后果","从库网络延迟高时，client-output-buffer-limit 应该如何调整"],"tags":["Redis","主从复制","复制缓冲区","PSYNC"],"id":4132},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis 哨兵选主","content":"描述 Redis Sentinel 故障转移中的领导者选举过程。主观下线（SDOWN）和客观下线（ODOWN）如何判定？Sentinel 之间如何通过类 Raft 共识选举 Leader？如何选择新主库？","answer":"Redis Sentinel 的故障转移流程：\\n\\n1. 主观下线（SDOWN）：\\n- 单个 Sentinel 检测到 master 在 down-after-milliseconds 时间内没有响应 PING。\\n- 标记为 sdown 并通知其他 Sentinel。\\n\\n2. 客观下线（ODOWN）：\\n- 当 Sentinel 收到足够多（>= quorum）的 Sentinel 报告 master 不可达。\\n- 标记为 odown，触发 Leader 选举。\\n\\n3. Leader 选举（Raft 类共识）：\\n- 每个检测到 ODOWN 的 Sentinel 为自己投票（类似 Raft 的 Candidate）。\\n- 需获得超过一半 Sentinel 节点数（majority，非 quorum）的选票。\\n- 如果一轮未能选出（平票或不足 majority），随机退避后重试。\\n\\n4. 新主库选择（由选出的 Leader 执行）：\\n- 过滤：排除已下线和不在线的从库，排除最近断连过的从库。\\n- 优先级：按 replica-priority（越小越优先）。\\n- 复制进度：选择与主库复制偏移量最大的从库。\\n- 运行 ID：如果优先级和偏移量相同，选择 run ID 最小的。\\n\\n5. 故障转移执行：\\n- 选中的从库执行 SLAVEOF NO ONE 升级为主库。\\n- 其他从库重新配置为跟随新主库。\\n- 原主库恢复后降级为从库。","hints":["SDOWN 和 ODOWN 的关键区别是什么","选举 Leader 需要 majority 还是 quorum？两者有什么不同"],"tags":["Redis","哨兵","选主","高可用","Raft"],"id":4133},{"category":"redis_extras","difficulty":"medium","type":"short_answer","title":"Redis 6 多线程 IO","content":"解释 Redis 6 引入的多线程 IO 模型。哪些操作是线程化的？哪些操作仍然是单线程的？什么场景下多线程 IO 有显著收益？配置参数有哪些？","answer":"Redis 6 多线程 IO 模型：\\n\\n设计原则：\\n- 命令执行（核心数据处理）仍然是单线程的——保证原子性和数据一致性。\\n- 多线程仅用于网络 IO 的读写操作。\\n\\n线程化的部分：\\n1. 从客户端 Socket 读取数据——多线程并行读取。\\n2. 将命令执行结果写回客户端 Socket——多线程并行写入。\\n\\n仍为单线程的部分：\\n- 命令解析和执行。\\n- 数据结构的修改和查询。\\n- RDB/AOF 持久化操作（有独立的子进程/子线程）。\\n\\n配置参数：\\n- io-threads：IO 线程数（默认 4），通常设置为 CPU 核数。\\n- io-threads-do-reads：是否启用多线程读（默认 no，即默认只多线程写）。\\n\\n性能收益：\\n- 大批量数据（如 MGET、大量 pipelined 操作）场景收益显著。\\n- 大量并发连接的场景受益于网络 IO 并行化。\\n- 小命令、低并发场景收益有限。\\n\\n注意事项：\\n- io-threads 不宜超过 CPU 核数，否则上下文切换会抵消收益。\\n- 命令执行仍是单线程瓶颈，对 CPU 密集型命令（如 KEYS、SORT）无帮助。\\n- 启用在有大量并发连接和大数据传输的场景最有效。","hints":["多线程 IO 不改动哪一部分处理流程","什么业务场景下开启多线程 IO 收益最大"],"tags":["Redis","多线程","IO","性能"],"id":4134},{"category":"redis_extras","difficulty":"medium","type":"short_answer","title":"Redis Stream 消费者组","content":"解释 Redis Stream 消费者组（Consumer Group）的工作机制。消息如何在不同消费者之间分配？PEL（Pending Entries List）的作用是什么？如何处理消费者故障和消息重新分配？","answer":"Redis Stream 消费者组机制：\\n\\n核心概念：\\n- 消费者组 = 一组消费者协同消费同一个 Stream。\\n- 每条消息在组内只分发给一个消费者（不同于 Pub/Sub）。\\n- 每个组独立维护消费状态。\\n\\n消息分配：\\n- XREADGROUP GROUP group consumer 从 Stream 读取消息。\\n- 默认采用轮询（Round-Robin）方式在组内消费者间分配消息。\\n- 消费者需通过 XACK 确认消息已处理完成。\\n\\nPEL（Pending Entries List）：\\n- 每个消费者维护一个 PEL，记录已投递但未 ACK 的消息。\\n- 保证至少一次（At-Least-Once）语义——消费者崩溃后消息不会被丢弃。\\n- XPENDING 可查看 PEL 状态（消息 ID、所属消费者、空闲时间、投递次数）。\\n\\n故障处理：\\n1. XCLAIM：将指定消息的所有权从一个消费者转移给另一个消费者。\\n   - 需指定 MIN-IDLE-TIME（这条消息未 ACK 的空闲最小时间）。\\n2. XAUTOCLAIM（Redis 7.0+）：自动扫描 PEL 并回收超时未 ACK 的消息。\\n3. 被回收的消息投递计数（delivery count）会递增。\\n\\n与 Kafka 的区别：\\n- Redis Stream 不会自动 rebalance——新消费者加入后仍需手动分配。\\n- 没有 Kafka 的 Consumer Group Coordinator 角色。\\n\\n使用建议：\\n- XGROUP CREATE 创建组时指定 $（只消费之后的）或 0（从头消费）。\\n- 设置合理的 NACK（未确认）监控和告警。","hints":["Redis Stream 的 PEL 如何实现至少一次投递","如果一个消费者崩溃了，其中的 PEL 消息怎么处理"],"tags":["Redis","Stream","消费者组","PEL"],"id":4135},{"category":"redis_extras","difficulty":"medium","type":"short_answer","title":"Lua 脚本原子性","content":"解释 Redis Lua 脚本的原子性保证。EVAL 和 EVALSHA 的执行语义是什么？脚本执行期间其他命令能否执行？如果脚本执行出错，已执行的命令会回滚吗？脚本如何复制到从库？","answer":"Redis Lua 脚本的原子性与复制机制：\\n\\n原子性语义：\\n- 脚本执行期间，Redis 会阻塞所有其他客户端命令。\\n- 脚本是一个整体原子操作——不会被其他命令中断。\\n- 但脚本失败不会回滚（Rollback）已执行的操作——Redis 没有回滚机制。\\n- 脚本中已执行的写命令即使后面出错，也会保持已写入状态。\\n\\nEVAL 与 EVALSHA：\\n- EVAL：直接发送脚本内容执行。\\n- EVALSHA：通过脚本的 SHA1 校验和执行（需先用 SCRIPT LOAD 缓存）。\\n- EVALSHA 在网络传输上更高效（短字符串代替长脚本）。\\n\\n脚本沙箱：\\n- 只提供有限的库函数（不提供文件 IO、网络 IO 等）。\\n- 通过 KEYS[i] 和 ARGV[i] 参数数组传递键名和参数（便于分析依赖）。\\n\\n复制机制：\\n- 默认模式（Redis 3.2+）：脚本作为整体复制到从库和 AOF。\\n- 如果脚本使用了「脚本效果复制」（script effects replication），且不含随机命令（TIME、SRANDMEMBER、SPOP 等），可作为单个写命令复制。\\n- 脚本必须具有确定性（Deterministic）——相同输入产生相同输出，否则主从数据不一致。\\n\\n使用建议：\\n- 脚本中所有键应通过 KEYS 数组传递以支持集群模式。\\n- 避免长时间运行的脚本（redis.conf 的 lua-time-limit 默认 5000ms）。\\n- 超时只会中断脚本，但不会自动终止——需要 SCRIPT KILL（如果未执行写操作）或 SHUTDOWN。","hints":["脚本执行一半出错后，前面的写操作会怎样","Redis 如何确保 Lua 脚本在从库上执行结果一致"],"tags":["Redis","Lua","原子性","复制"],"id":4136},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis Function 脚本引擎与 Lua EVAL 的对比","content":"Redis 7.0 引入了 Function（函数）功能作为 Lua 脚本的新执行方式。请说明 Redis Function 与传统的 EVAL/EVALSHA 的核心区别，以及 Function 解决了什么痛点。","answer":"答案：Redis Function 是 Redis 7.0 引入的脚本管理框架，允许用户注册命名函数到 Redis 服务端（通过 FUNCTION LOAD），然后通过 FCALL 调用。与 EVAL/EVALSHA 相比，Function 解决了脚本管理、复制安全性和跨库迁移的痛点。\n\n解析：传统 EVAL/EVALSHA 的问题：1）脚本管理分散——每个客户端各自 SCRIPT LOAD，不同客户端之间的脚本缓存不共享。2）重启丢失——Redis 重启后所有已缓存的脚本丢失，客户端需重新加载（NOSCRIPT 错误）。3）跨 Cluster 节点不一致——不同节点的脚本缓存可能不同步。Function 的改进：1）集中式注册——函数注册后存储在 Redis 服务器（通过 RDB/AOF 持久化），重启后仍然可用。2）复制安全——函数在写入 AOF 或同步到从节点时自动传播，无需担心 EVALSHA 的脚本缓存同步问题。3）库（Library）管理——支持按库组织函数，可通过 FUNCTION LIST/FUNCTION DELETE 管理。\n\n扩展延伸：Function 注册语法：FUNCTION LOAD REPLACE \"#!lua name=mylib\\nredis.register_function('myfunc', function(keys, args) return redis.call('GET', keys[1]) end)\"。FCALL 调用语法：FCALL myfunc 1 mykey。Function 仍然在沙箱中执行（与 EVAL 相同），且同样具有原子性。注意：Function 不是 Lua 语言的变化——它只是脚本管理和分发方式的改进。Redis 7.0+ 建议新项目优先使用 Function 替代 EVAL/EVALSHA。","hints":["为什么 EVALSHA 在 Redis Cluster 中容易出现 NOSCRIPT 错误","Function 如何解决跨节点脚本缓存不一致的问题"],"tags":["Redis","Function","Lua","Redis 7.0","脚本"],"id":4137},{"category":"redis_extras","difficulty":"medium","type":"choice","title":"Redis 异步删除（lazy-free）机制","content":"关于 Redis 4.0+ 引入的 lazy-free（异步释放内存）机制，以下说法正确的是？","options":["A) lazy-free 默认开启，所有删除操作都会异步执行","B) UNLINK 命令会立即将 key 从键空间中删除，并在后台线程释放内存，因此不会阻塞主线程","C) lazy-free 只对 DEL 命令生效，对 EXPIRE 命令不生效","D) FLUSHALL ASYNC 与 FLUSHALL 性能完全一致"],"answer":"答案：B) UNLINK 命令会立即将 key 从键空间中删除，并在后台线程释放内存，因此不会阻塞主线程\n\n解析：Redis 4.0 引入 lazy-free 机制（lazyfree-lazy-user-del=no 默认关闭），通过 UNLINK 命令显式触发异步删除，主线程 O(1) 从键空间中摘除 key 后立即返回，实际内存回收在后台线程逐步进行。DEL 命令默认是同步的（大 key 的 DEL 可能阻塞 Redis 数十秒）。lazy-free 相关配置：1）lazyfree-lazy-eviction=yes——淘汰 key 时异步释放。2）lazyfree-lazy-expire=yes——过期 key 异步释放。3）lazyfree-lazy-server-del=yes——隐式删除（如 rename 覆盖）异步释放。4）replica-lazy-flush=yes——从节点全量同步时的 FLUSHALL 异步释放。\n\n扩展延伸：UNLINK 的底层实现：先判断 key 的类型和大小。如果 key 很小（如短的 String），UNLINK 退化为同步 DEL（后台线程开销 > 直接释放）。只有大 key（集合类元素多或值大的 String）才会真正异步释放。后台线程通过 BIO（Background I/O）线程池执行释放操作，避免主线程阻塞。监控：INFO stats 中的 lazy_free_passes 和 lazy_freed_objects 统计异步释放的对象数。","hints":["lazy-free 何时退化为同步 DEL——UNLINK 的判断条件是什么","lazyfree-lazy-eviction 和 lazyfree-lazy-expire 分别控制什么场景的异步删除"],"tags":["Redis","lazy-free","UNLINK","性能","阻塞"],"id":4138},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis listpack 如何解决 ziplist 的连锁更新问题","content":"Redis 7.0 用 listpack 全面取代了 ziplist。ziplist 存在什么连锁更新（Cascade Update）问题？listpack 是如何解决这个问题的？","answer":"答案：ziplist 的连锁更新问题源于其节点的 prevlen 字段采用可变长度编码——当新增或修改一个节点导致其后续节点的 prevlen 需要从 1 字节扩展到 5 字节时，可能引发一连串的 prevlen 重新计算。listpack 通过去除前向长度字段，改为每个节点记录自身长度（包含尾部），消除了连锁更新的根源。\n\n解析：ziplist 的连锁更新：1）ziplist 每个节点包含 prevlen（前一个节点的长度）和 encoding+data。2）prevlen 的编码规则：如果前一个节点长度 < 254 字节，prevlen 用 1 字节；>= 254 字节则用 5 字节（第一个字节 0xFE 作为标记）。3）连锁更新触发场景：往 ziplist 中间插入一个 253 字节的节点后，其后续节点需要扩展 prevlen；如果扩展后该节点也达到 254 字节，再后续的节点也需要扩展——形成链式反应。最坏情况下复杂度 O(n²)。listpack 的改进：listpack 每个节点只记录 self-length（自身长度，通过 encoding 字段尾部计算出总长度），不依赖前一个节点的信息来定位。因此插入或删除一个节点时不需要级联更新后续节点的头部字段。\n\n扩展延伸：listpack 的遍历方式：通过每个节点末尾的 total-bytes 信息反向定位前一个节点（从尾部开始减），不需要 forward/backward 指针。listpack 在 Redis 7.0 中替换了 ziplist 的所有使用场景：Hash 的 field 少时用 listpack、Zset 元素少时用 listpack、List 的 quicklist 节点内用 listpack（替代 ziplist）。连锁更新的实际影响：虽然在典型场景下发生的概率很低，但一旦发生会造成不可预测的延迟抖动。listpack 从数据结构层面根除了此问题。","hints":["ziplist 的 prevlen 为什么使用可变长度编码","listpack 如何在不存储前向长度的情况下反向遍历"],"tags":["Redis","listpack","ziplist","连锁更新","数据结构"],"id":4139},{"category":"redis_extras","difficulty":"medium","type":"choice","title":"Redis 7.0 Sharded Pub/Sub","content":"关于 Redis 7.0 引入的 Sharded Pub/Sub（SSUBSCRIBE/SPUBLISH），以下说法正确的是？","options":["A) Sharded Pub/Sub 对所有订阅者广播消息，与传统 Pub/Sub 功能完全相同","B) Sharded Pub/Sub 将消息分片到固定的哈希槽，确保同一频道消息在不同槽位均匀分布","C) Sharded Pub/Sub 将频道按 key 的哈希槽映射到集群节点，消息只广播到同一槽位的节点上，避免跨节点扩散","D) Sharded Pub/Sub 使用 Stream 作为消息存储后端"],"answer":"答案：C) Sharded Pub/Sub 将频道按 key 的哈希槽映射到集群节点，消息只广播到同一槽位的节点上，避免跨节点扩散\n\n解析：传统 PUB/SUB 在 Redis Cluster 中有一个严重问题——当客户端通过任意节点 PUBLISH 消息时，该节点必须将消息广播到集群内所有其他节点（cluster links），以确保所有订阅该频道的客户端都能收到。这意味着集群中每个 PUBLISH 都会产生 N-1 次内部节点间转发，在频道多、消息频繁的集群中造成巨大的内部网络开销。Sharded Pub/Sub（Redis 7.0+）通过 SSUBSCRIBE/SPUBLISH 解决：频道名按 CRC16 计算哈希槽，消息只发送到负责该槽位的节点上，订阅该频道的客户端也必须连接到该节点。这样避免跨节点广播，消除了内部转发开销。\n\n扩展延伸：SSUBSCRIBE 与传统 SUBSCRIBE 的区别：1）S 版本的消息只在单节点处理，不跨节点广播。2）客户端需要连接到正确的节点（负责频道对应 slot 的节点）。3）SPUBLISH 不会广播给集群内其他节点——这消除了 Cluster 模式下 Pub/Sub 的扩展性瓶颈。适用场景：高频道数+高发布频率的 Redis Cluster 场景。迁移注意：传统 SUBSCRIBE 和 SSUBSCRIBE 是两套独立的频道空间——同一个频道名在两组中的消息互不传递。","hints":["传统 Pub/Sub 在 Cluster 模式下为什么会产生 N-1 次内部转发","Sharded Pub/Sub 如何确保客户端连接到正确的节点"],"tags":["Redis","Sharded Pub/Sub","Redis 7.0","Cluster"],"id":4140},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis 无盘复制（Diskless Replication）","content":"Redis 全量同步时主节点需要生成 RDB 快照传给从节点。传统方式使用磁盘 RDB，Redis 7.0+ 优化了无盘复制。请说明 diskless replication 的工作原理，以及它解决了什么问题。","answer":"答案：Diskless Replication（无盘复制）是 Redis 2.8.18+ 引入的优化（通过 repl-diskless-sync yes 开启），主节点在生成 RDB 快照后不写入磁盘文件，而是通过 Socket 直接流式发送给从节点，减少磁盘 I/O 开销和延迟。Redis 7.0+ 进一步优化了无盘复制的并发处理能力。\n\n解析：传统 RDB 全量同步：1）主节点 fork 子进程生成 RDB 文件到磁盘。2）子进程完成 RDB 写入后通知主进程。3）主进程读取 RDB 文件并逐块发送给从节点。问题：RDB 文件写入磁盘和从磁盘读取都是 I/O 密集型操作，磁盘成为瓶颈，且父进程在读取 RDB 时可能因大文件读取阻塞事件循环。无盘复制：1）主节点 fork 子进程后，子进程直接将 RDB 内容写入从节点的 Socket（不经过磁盘）。2）数据从内存直接到网络，避免了两次磁盘 I/O（写 RDB 文件 + 读 RDB 文件）。\n\n扩展延伸：Redis 7.0+ 的改进：repl-diskless-sync-max-replicas（默认 0，表示不限制）——主节点等待更多从节点同时发起全量同步，一次 RDB 生成服务多个从节点，进一步降低 fork 频率。延迟补偿：无盘复制中主节点会先将生成的 RDB 写入一个中间 Socket 缓冲区（repl-backlog），断开重连的从节点可以从中追回部分数据，减少全量同步频率。适用建议：磁盘慢（如 HDD 或共享存储）但网络带宽充足的场景优先开启无盘复制；磁盘快（NVMe SSD）且从节点少的场景两者差异不大。","hints":["无盘复制为什么能减少主节点的延迟抖动","repl-diskless-sync-max-replicas 参数的作用是什么"],"tags":["Redis","无盘复制","Diskless Replication","主从复制","全量同步"],"id":4141},{"category":"redis_extras","difficulty":"medium","type":"short_answer","title":"Redis RESP3 协议与 HELLO 握手","content":"Redis 6.0 引入了 RESP3 协议。RESP3 相比 RESP2 有哪些核心改进？HELLO 命令在新的协议协商中扮演什么角色？RESP3 对客户端库设计有什么影响？","answer":"答案：RESP3（REdis Serialization Protocol version 3）相比 RESP2 的核心改进是引入更丰富的数据类型——Map、Set、Push、Bool、Null、Double、Big Number、Streamed String 等，使客户端无需猜测响应语义。\n\n解析：HELLO 命令是 RESP3 的协议协商入口：客户端发送 HELLO 3 协商切换到 RESP3，HELLO 2 降级为 RESP2。RESP3 的关键类型：Map（有序键值对，替代 RESP2 的 flat array 表示）、Push（服务器主动推送的类型，用于 Pub/Sub 和 Client-side caching invalidation 消息）、Set（无序集合）、Null（区分 nil 和空数组）。RESP3 也支持客户端缓存（Client-side Caching）的推送通知。\n\n扩展延伸：RESP3 使用 $? 前缀表示空值、% 前缀表示 Map、> 前缀表示 Push。客户端库需要重新实现解析器，但不是所有 Redis 命令都使用了 RESP3 类型（很多仍返回 RESP2 兼容格式）。Redis 6+ 默认仍使用 RESP2。","hints":["RESP3 比 RESP2 多了哪些数据类型","HELLO 命令的作用是什么"],"tags":["Redis","RESP3","协议","客户端"],"id":4152},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis WAITAOF 命令与持久化确认","content":"Redis 7.2 引入了 WAITAOF 命令。请说明 WAITAOF 的作用、使用场景和实现原理，以及它与 WAIT 命令的异同。","answer":"答案：WAITAOF 命令阻塞当前客户端直到所有之前执行的写命令的 AOF 日志被写入指定数量的从节点磁盘（fsync 完成）。\n\n解析：WAITAOF 解决了从节点宕机后 AOF 日志落后导致的数据丢失问题。语法：WAITAOF numreplicas timeout。与 WAIT 命令的区别：WAIT 等待的是从节点确认已接收（写入内存），不保证 fsync 到磁盘；WAITAOF 等待从节点确认已将 AOF buffer fsync 到磁盘文件。实现原理：主节点在写命令传播后，跟踪每个从节点的 AOF fsync 状态。当从节点返回 REPLCONF ack 同时携带 fsync 偏移量，主节点与 WAITAOF 请求的期待偏移量比较，达到要求后唤醒阻塞的客户端。\n\n扩展延伸：WAITAOF 仅对开启了 AOF 的从节点有效。如果从节点没有开启 AOF，WAITAOF 不考虑它。timeout=0 表示无限等待。配合 Redis 7.2 的 AOF on-disk SHA 校验使用可以实现端到端的持久化确认。","hints":["WAITAOF 等待的是什么粒度的确认","WAITAOF 与 WAIT 的核心区别是什么"],"tags":["Redis","AOF","持久化","数据安全"],"id":4153},{"category":"redis_extras","difficulty":"medium","type":"choice","title":"Redis SWAPDB 命令与数据库切换","content":"关于 Redis SWAPDB 命令，以下说法正确的是？","answer":"答案：B) SWAPDB 使用 O(1) 操作交换两个数据库的全部键空间，无需遍历数据\n\n解析：SWAPDB db1 db2 通过原子交换两个数据库的 dict 指针实现，不复制或迁移实际数据。执行后 db1 和 db2 的内容互换，对其他连接的可见性由 Redis 的事务原子性保证。此命令常用于数据库「挪移」——先在新编号写数据，然后原子交换到旧编号，实现零停机切换。\n\n扩展延伸：SWAPDB 不会触发过期键检查或主动淘汰，但交换后键的过期时间保持不变。交换过程中 Redis 是阻塞的（单线程执行命令）。FLUSHDB 配合 SWAPDB 可设计无阻塞的清空方案：FLUSHDB db1 后 SAVE/RDB 仍存在问题，但 SWAPDB 到临时编号+FLUSHDB 原编号在某些模式中很实用。","options":["A) SWAPDB 会遍历整个数据库逐个复制键值","B) SWAPDB 使用 O(1) 操作交换两个数据库的全部键空间，无需遍历数据","C) SWAPDB 交换后键的过期时间会被重置","D) SWAPDB 只能交换当前选中的数据库"],"hints":["SWAPDB 的数据结构基础是什么","SWAPDB 的典型使用场景"],"tags":["Redis","SWAPDB","运维","原子操作"],"id":4154},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis MIGRATE 命令与槽迁移原理","content":"Redis 的 MIGRATE 命令如何实现 key 在实例间的迁移？在 Cluster 模式下，MIGRATE 与 CLUSTER SETSLOT 如何配合完成槽迁移？MIGRATE 的原子性和性能特性是什么？","answer":"答案：MIGRATE 是一条原子命令，将指定 key 从当前实例序列化传输到目标实例并删除本地副本。语法：MIGRATE host port key| destination-db timeout [COPY] [REPLACE] [KEYS key1 ...]。\n\n解析：Cluster 槽迁移流程：1）CLUSTER SETSLOT slot IMPORTING src-node（目标节点标记槽为 importing）。2）CLUSTER SETSLOT slot MIGRATING dst-node（源节点标记槽为 migrating）。3）对槽内每个 key 执行 MIGRATE 传输。4）MIGRATE 内部使用 DUMP + RESTORE 命令——先序列化 key 的 RDB 格式数据到缓冲区，传输到目标调用 RESTORE，然后在本地 DEL。5）传输完成后 CLUSTER SETSLOT slot NODE dst-node 广播槽归属变更。使用 COPY 选项可保留源端 key（用于复制而非迁移）。REPLACE 选项覆盖目标已存在的 key。\n\n扩展延伸：MIGRATE 是阻塞命令，传输大 key 会导致 Redis 卡顿。批量迁移使用 MIGRATE ... KEYS key1 key2（Redis 3.0.6+）。Redis Cluster 的 live rehashing 在迁移过程中源节点仍可处理该槽请求，找不到 key 时返回 ASK 转向，客户端需要实现 ASK redirection。","hints":["MIGRATE 内部使用了哪两个命令","Cluster 槽迁移中 IMPORTING 和 MIGRATING 状态的作用"],"tags":["Redis","MIGRATE","集群迁移","Cluster"],"id":4155},{"category":"redis_extras","difficulty":"hard","type":"short_answer","title":"Redis ACL LOG 与安全审计","content":"Redis 6.0 引入了 ACL LOG 机制。请说明 ACL LOG 的作用、日志条目包含哪些信息，以及它与普通 Redis 日志的区别。如何通过 ACL 机制实现生产环境的安全审计？","answer":"答案：ACL LOG 是 Redis 6.0 ACL 子系统的一部分，记录因 ACL 权限不足被拒绝的命令以及其他 ACL 相关事件，帮助运维人员定位配置问题。\n\n解析：ACL LOG 通过 ACL LOG 命令查看，ACL LOG RESET 清除。日志条目包含以下字段：count（同一类违规次数）、reason（违规原因——command/role/user/auth）、object（违规的命令名/用户名）、username（发起用户）、age（距上次违规的秒数）、time（首次违规时间戳）、client-id/client-name。它与 Redis 普通日志的区别：ACL LOG 保存在内存中的循环缓冲区（由 acllog-max-len 控制，默认 128 条），不是写入文件日志，专门用于 ACL 审计，不记录其他系统事件。\n\n扩展延伸：ACL LOG 支持多种 reason：auth（认证失败）、command（命令无权限）、role（角色问题）、selinux（忽略）、no-perms（无权限认证）等。安全审计建议：将 acllog-max-len 调大，定期通过 ACL LOG 检查异常访问模式，结合监控系统报警频繁的 ACL 拒绝事件。ACL 配置文件（users.acl）建议启用 aclfile 模式而非 config 模式以确保持久化。","hints":["ACL LOG 保存在内存还是文件","ACL LOG 包含了哪些违规原因类型"],"tags":["Redis","ACL","安全审计","访问控制"],"id":4156}];
